impl Solution { pub fn minimum_cost(black_s: String, black_t: String, black_f: i32, black_s_c: i32, black_c_c: i32) -> i64 { let (black_s_b, black_t_b) = (black_s.as_bytes(), black_t.as_bytes()); let (mut black_c0, mut black_c1) = (0i64, 0i64); for black_i in 0..black_s_b.len() { if black_s_b[black_i] != black_t_b[black_i] { if black_s_b[black_i] == b'0' { black_c0 += 1; } else { black_c1 += 1; } } } let (black_f, black_s_c, black_c_c) = (black_f as i64, black_s_c as i64, black_c_c as i64); let black_r1 = (black_c0 + black_c1) * black_f; let black_r2 = black_c0.min(black_c1) * black_s_c + (black_c0 - black_c1).abs() * black_f; let black_r3 = black_c0.min(black_c1) * black_s_c + ((black_c0 - black_c1).abs() / 2) * (black_s_c + black_c_c) + ((black_c0 - black_c1).abs() % 2) * black_f; black_r1.min(black_r2).min(black_r3) } }